// ============================================================
// Evolution Tracking — Changes between Aulas
// ============================================================

function normalizeId(id: string) { return id.replace(/\s/g, '').toUpperCase(); }

type EvolutionEntry = { riskId: string; type: 'new' | 'modified' | 'unchanged'; changes: string[] };

function computeEvolution(from: Risk[], to: Risk[]): EvolutionEntry[] {
  const fromMap = new Map(from.map(r => [normalizeId(r.id), r]));
  const fromIds = new Set(from.map(r => normalizeId(r.id)));
  return to.map(r => {
    const rid = normalizeId(r.id);
    if (!fromIds.has(rid)) return { riskId: rid, type: 'new' as const, changes: ['Novo risco (não existia na versão anterior)'] };
    const prev = fromMap.get(rid)!;
    const changes: string[] = [];
    if (prev.gutScore !== r.gutScore) changes.push(`GUT: ${prev.gutScore}→${r.gutScore}`);
    if (prev.riscoInerente !== r.riscoInerente) changes.push(`PxI: ${prev.riscoInerente}→${r.riscoInerente}`);
    if (prev.tratamento !== r.tratamento && r.tratamento) changes.push('Tratamento atualizado');
    if (r.controles && (!prev.controles || r.controles.length > prev.controles.length + 20)) changes.push('Controles detalhados');
    if (r.kri && !prev.kri) changes.push('KRI definido');
    if (r.consequencia && !prev.consequencia) changes.push('Consequência detalhada');
    if (r.eficaciaTratamento && !prev.eficaciaTratamento) changes.push('Eficácia definida');
    if (changes.length > 0) return { riskId: rid, type: 'modified' as const, changes };
    return { riskId: rid, type: 'unchanged' as const, changes: [] };
  });
}

export const EVOLUTION_3_TO_4 = computeEvolution(RISKS_AULA3, RISKS_AULA4);
export const EVOLUTION_4_TO_5 = computeEvolution(RISKS_AULA4, RISKS_AULA5);
export const EVOLUTION_SUMMARY = EVOLUTION_4_TO_5;
